      { theme: "error", variant: "outline", class: "border-(--badge-error-outline-border) text-(--badge-error-outline-fg)" },
      { theme: "error", variant: "ghost", class: "text-(--badge-error-ghost-fg)" },
      { theme: "warning", variant: "solid", class: "bg-(--badge-warning-solid-bg) text-(--badge-warning-solid-fg)" },
      { theme: "warning", variant: "subtle", class: "bg-(--badge-warning-subtle-bg) text-(--badge-warning-subtle-fg)" },
      { theme: "warning", variant: "outline", class: "border-(--badge-warning-outline-border) text-(--badge-warning-outline-fg)" },
      { theme: "warning", variant: "ghost", class: "text-(--badge-warning-ghost-fg)" },
      { theme: "success", variant: "solid", class: "bg-(--badge-success-solid-bg) text-(--badge-success-solid-fg)" },
      { theme: "success", variant: "subtle", class: "bg-(--badge-success-subtle-bg) text-(--badge-success-subtle-fg)" },
      { theme: "success", variant: "outline", class: "border-(--badge-success-outline-border) text-(--badge-success-outline-fg)" },
      { theme: "success", variant: "ghost", class: "text-(--badge-success-ghost-fg)" },
      { theme: "info", variant: "solid", class: "bg-(--badge-info-solid-bg) text-(--badge-info-solid-fg)" },
      { theme: "info", variant: "subtle", class: "bg-(--badge-info-subtle-bg) text-(--badge-info-subtle-fg)" },
      { theme: "info", variant: "outline", class: "border-(--badge-info-outline-border) text-(--badge-info-outline-fg)" },
      { theme: "info", variant: "ghost", class: "text-(--badge-info-ghost-fg)" },
    ],
    defaultVariants: {
      theme: "default",
      variant: "solid",
      size: "md",
    },
  },
);
export type BadgeProps = Omit<ComponentPropsWithoutRef<typeof ark.span>, "prefix" | "suffix"> &
  VariantProps<typeof badgeVariants> & {
    prefix?: ReactNode;
    suffix?: ReactNode;
  };
export function Badge({
  className,
  theme,
  variant,
  size,
  prefix,
  suffix,
  children,
  ...props
}: BadgeProps) {
  return (
    <ark.span
      className={cn(badgeVariants({ theme, variant, size }), className)}
      {...props}
    >
      {prefix ? <span className="inline-flex shrink-0 items-center">{prefix}</span> : null}
      {children}
      {suffix ? <span className="inline-flex shrink-0 items-center">{suffix}</span> : null}
    </ark.span>
  );
}

