      size: {
        sm: "size-(--breadcrumb-sm-ellipsis-size) [&_svg]:size-(--breadcrumb-sm-icon-size)",
        md: "size-(--breadcrumb-md-ellipsis-size) [&_svg]:size-(--breadcrumb-md-icon-size)",
      },
    },
    defaultVariants: {
      size: "md",
    },
  },
);

const breadcrumbMenuContentClass =
  "z-50 min-w-(--breadcrumb-menu-min-width) rounded-(--breadcrumb-menu-radius) border border-(--breadcrumb-menu-border) bg-(--breadcrumb-menu-bg) p-1 text-(--breadcrumb-menu-fg) shadow-(--breadcrumb-menu-shadow) outline-none";

const breadcrumbMenuItemClass =
  "flex w-full cursor-pointer items-center gap-2 rounded-(--breadcrumb-menu-item-radius) px-(--breadcrumb-menu-item-px) py-(--breadcrumb-menu-item-py) [font-size:var(--breadcrumb-menu-item-font-size)] text-(--breadcrumb-menu-fg) outline-none data-[highlighted]:bg-(--breadcrumb-menu-item-highlight-bg) data-[highlighted]:text-(--breadcrumb-menu-item-highlight-fg) [&_svg]:size-(--breadcrumb-sm-icon-size)";

type BreadcrumbSize = NonNullable<VariantProps<typeof breadcrumbInteractiveVariants>["size"]>;
type BreadcrumbSeparatorType = "slash" | "chevron";

export type BreadcrumbCollapsedItem = {
  value: string;
  label: ReactNode;
  href?: string;
  prefix?: ReactNode;
};

type BreadcrumbContextValue = {
  size: BreadcrumbSize;
  separator: BreadcrumbSeparatorType;
  maxItems?: number;
  itemsBeforeCollapse: number;
  itemsAfterCollapse?: number;
};

const BreadcrumbContext = createContext<BreadcrumbContextValue>({
  size: "md",
  separator: "slash",
  itemsBeforeCollapse: 1,
});

function useBreadcrumbContext(): BreadcrumbContextValue {
  return useContext(BreadcrumbContext);
}

export type BreadcrumbProps = ComponentPropsWithoutRef<"nav"> &
  VariantProps<typeof breadcrumbInteractiveVariants> & {
    separator?: BreadcrumbSeparatorType;
    maxItems?: number;
    itemsBeforeCollapse?: number;
    itemsAfterCollapse?: number;
  };

export type BreadcrumbLinkProps = Omit<ComponentPropsWithoutRef<typeof ark.a>, "prefix"> & {
  prefix?: ReactNode;
};

export type BreadcrumbPageProps = Omit<ComponentPropsWithoutRef<"span">, "prefix"> & {
  prefix?: ReactNode;
};

export type BreadcrumbEllipsisProps = Omit<ComponentPropsWithoutRef<"button">, "prefix"> & {
  items?: BreadcrumbCollapsedItem[];
};

type BreadcrumbPartName = "BreadcrumbItem" | "BreadcrumbLink" | "BreadcrumbPage";

function getPartName(type: unknown): string | undefined {
  if (typeof type === "function") {
    return (type as { displayName?: string }).displayName;
  }
  if (typeof type === "object" && type !== null && "displayName" in type) {
    return (type as { displayName?: string }).displayName;
  }
  return undefined;
}

function isBreadcrumbPart(element: unknown, name: BreadcrumbPartName): element is ReactElement {
  return isValidElement(element) && getPartName(element.type) === name;
}

function extractCollapsedItem(element: ReactElement, index: number): BreadcrumbCollapsedItem | null {
  const child = Children.only(element.props.children);
  if (!isValidElement(child)) return null;

  if (isBreadcrumbPart(child, "BreadcrumbLink")) {
    const props = child.props as BreadcrumbLinkProps;
    return {
      value: `collapsed-link-${index}`,
      label: props.children,
      href: props.href,
      prefix: props.prefix,
    };
  }

  if (isBreadcrumbPart(child, "BreadcrumbPage")) {
    const props = child.props as BreadcrumbPageProps;
    return {
      value: `collapsed-page-${index}`,
      label: props.children,
      prefix: props.prefix,
    };
  }

  return null;
}

function Breadcrumb({
  className,
  size = "md",
  separator = "slash",
  maxItems,
  itemsBeforeCollapse = 1,
  itemsAfterCollapse,
  children,
  ...props
}: BreadcrumbProps) {
  const contextValue = useMemo(
    () => ({
      size: size ?? "md",
      separator: separator ?? "slash",
      maxItems,
      itemsBeforeCollapse: itemsBeforeCollapse ?? 1,
      itemsAfterCollapse,
    }),
    [size, separator, maxItems, itemsBeforeCollapse, itemsAfterCollapse],
  );

  return (
    <BreadcrumbContext.Provider value={contextValue}>
      <nav aria-label="Breadcrumb" className={cn(className)} {...props}>
        {children}
      </nav>
    </BreadcrumbContext.Provider>
  );
}

function BreadcrumbList({
  className,
  children,
  ...props
}: ComponentPropsWithoutRef<"ol">) {
  const { maxItems, itemsBeforeCollapse, itemsAfterCollapse } = useBreadcrumbContext();
  const itemElements = Children.toArray(children).filter((child) =>
    isBreadcrumbPart(child, "BreadcrumbItem"),
  );

  const plan =
    maxItems != null
      ? getCollapsePlan(
          itemElements.length,
          maxItems,
          itemsBeforeCollapse,
          itemsAfterCollapse,
        )
      : null;

  if (!plan) {
    return (
      <ol
        className={cn(
          "flex flex-wrap items-center gap-(--breadcrumb-list-gap) text-(--breadcrumb-link-fg)",
          className,
        )}
        {...props}
      >
        {children}
      </ol>
    );
  }

  const beforeItems = itemElements.slice(0, plan.before);
  const afterItems = itemElements.slice(plan.afterStart);
  const collapsedItems = itemElements
    .slice(plan.before, plan.afterStart)
    .map((item, index) => extractCollapsedItem(item as ReactElement, index))
    .filter(Boolean);

  const segments = [
    ...beforeItems.map((item, index) => ({ key: `before-${index}`, type: "item", item })),
    { key: "ellipsis", type: "ellipsis", items: collapsedItems },
    ...afterItems.map((item, index) => ({ key: `after-${index}`, type: "item", item })),
  ];

  return (
    <ol
      className={cn(
        "flex flex-wrap items-center gap-(--breadcrumb-list-gap) text-(--breadcrumb-link-fg)",
        className,
      )}
      {...props}
    >
      {segments.map((segment, index) => (
        <Fragment key={segment.key}>
          {index > 0 ? <BreadcrumbSeparator /> : null}
          {segment.type === "ellipsis" ? (
            <BreadcrumbItem>
              <BreadcrumbEllipsis items={segment.items} />
            </BreadcrumbItem>
          ) : (
            segment.item
          )}
        </Fragment>
      ))}
    </ol>
  );
}
BreadcrumbList.displayName = "BreadcrumbList";

function BreadcrumbItem({
  className,
  ...props
}: ComponentPropsWithoutRef<"li">) {
  return <li className={cn("inline-flex items-center", className)} {...props} />;
}
BreadcrumbItem.displayName = "BreadcrumbItem";

function BreadcrumbLink({
  className,
  prefix,
  children,
  ...props
}: BreadcrumbLinkProps) {
  const { size } = useBreadcrumbContext();

  return (
    <ark.a
      className={cn(
        breadcrumbInteractiveVariants({ size }),
        "text-(--breadcrumb-link-fg) hover:text-(--breadcrumb-link-hover-fg)",
        className,
      )}
      {...props}
    >
      {prefix ? <span className="inline-flex shrink-0 items-center">{prefix}</span> : null}
      {children}
    </ark.a>
  );
}
BreadcrumbLink.displayName = "BreadcrumbLink";

function BreadcrumbPage({
  className,
  prefix,
  children,
  ...props
}: BreadcrumbPageProps) {
  const { size } = useBreadcrumbContext();

  return (
    <span
      aria-current="page"
      className={cn(
        breadcrumbPageVariants({ size }),
        "text-(--breadcrumb-page-fg)",
        className,
      )}
      {...props}
    >
      {prefix ? <span className="inline-flex shrink-0 items-center">{prefix}</span> : null}
      {children}
    </span>
  );
}
BreadcrumbPage.displayName = "BreadcrumbPage";

function BreadcrumbSeparator({
  className,
  children,
  ...props
}: ComponentPropsWithoutRef<"li">) {
  const { size, separator } = useBreadcrumbContext();

  return (
    <li
      role="presentation"
      aria-hidden="true"
      className={cn(breadcrumbSeparatorVariants({ size }), className)}
      {...props}
    >
      {children ?? (separator === "chevron" ? <ChevronRight aria-hidden="true" /> : "/")}
    </li>
  );
}
BreadcrumbSeparator.displayName = "BreadcrumbSeparator";

function BreadcrumbEllipsis({
  className,
  items,
  ...props
}: BreadcrumbEllipsisProps) {
  const { size } = useBreadcrumbContext();
  const [open, setOpen] = useState(false);
  const closeTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const clearCloseTimer = () => {
    if (closeTimerRef.current != null) {
      clearTimeout(closeTimerRef.current);
      closeTimerRef.current = null;
    }
  };

  const scheduleClose = () => {
    clearCloseTimer();
    closeTimerRef.current = setTimeout(() => setOpen(false), 120);
  };

  if (!items?.length) {
    return (
      <button
        type="button"
        aria-label="More pages"
        className={cn(breadcrumbEllipsisVariants({ size }), className)}
        {...props}
      >
        <MoreHorizontal aria-hidden="true" />
      </button>
    );
  }

  return (
    <Menu.Root
      open={open}
      onOpenChange={(details) => setOpen(details.open)}
      positioning={{ placement: "bottom-start", gutter: 4, strategy: "fixed" }}
      closeOnSelect
    >
      <Menu.Trigger asChild>
        <button
          type="button"
          aria-label="Show collapsed pages"
          aria-haspopup="menu"
          className={cn(breadcrumbEllipsisVariants({ size }), className)}
          onMouseEnter={() => {
            clearCloseTimer();
            setOpen(true);
          }}
          onMouseLeave={scheduleClose}
          {...props}
        >
          <MoreHorizontal aria-hidden="true" />
        </button>
      </Menu.Trigger>
      <Menu.Positioner>
        <Menu.Content
          className={breadcrumbMenuContentClass}
          onMouseEnter={clearCloseTimer}
          onMouseLeave={scheduleClose}
        >
          {items.map((item) =>
            item.href ? (
              <Menu.Item key={item.value} value={item.value} asChild>
                <a href={item.href} className={breadcrumbMenuItemClass}>
                  {item.prefix ? (
                    <span className="inline-flex shrink-0 items-center">{item.prefix}</span>
                  ) : null}
                  {item.label}
                </a>
              </Menu.Item>
            ) : (
              <Menu.Item key={item.value} value={item.value} className={breadcrumbMenuItemClass}>
                {item.prefix ? (
                  <span className="inline-flex shrink-0 items-center">{item.prefix}</span>
                ) : null}
                {item.label}
              </Menu.Item>
            ),
          )}
        </Menu.Content>
      </Menu.Positioner>
    </Menu.Root>
  );
}
BreadcrumbEllipsis.displayName = "BreadcrumbEllipsis";

export {
  Breadcrumb,
  BreadcrumbList,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbPage,
  BreadcrumbSeparator,
  BreadcrumbEllipsis,
};

/* Breadcrumb component tokens — override these to customise breadcrumbs. */
:root {
  --breadcrumb-list-gap: 2px;
  --breadcrumb-item-radius: var(--radius-md);
  --breadcrumb-ellipsis-radius: var(--radius-lg);

  /* duration-press-hover: 120–180ms for hover and press feedback */
  --breadcrumb-transition-duration: 150ms;
  --breadcrumb-transition-easing: ease-out;

  /* ux-fitts-hit-area: invisible expansion beyond visible bounds */
  --breadcrumb-hit-inset: -6px -8px;

  --breadcrumb-link-fg: var(--color-muted-foreground);
  --breadcrumb-link-hover-fg: var(--color-foreground);
  --breadcrumb-page-fg: var(--color-foreground);
  --breadcrumb-separator-fg: var(--color-muted-foreground);

  /* Size: sm — ux-fitts-target-size: min 32px interactive height */
  --breadcrumb-sm-py: 3px;
  --breadcrumb-sm-px: 4px;
  --breadcrumb-sm-font-size: 14px;
  --breadcrumb-sm-icon-size: 16px;
  --breadcrumb-sm-min-height: 32px;
  --breadcrumb-sm-ellipsis-size: 32px;

  /* Size: md */
  --breadcrumb-md-py: 5px;
  --breadcrumb-md-px: 5px;
  --breadcrumb-md-font-size: 16px;
  --breadcrumb-md-icon-size: 16px;
  --breadcrumb-md-min-height: 32px;
  --breadcrumb-md-ellipsis-size: 32px;

  /* Collapsed items menu (ellipsis dropdown) */
  --breadcrumb-menu-min-width: 160px;
  --breadcrumb-menu-radius: var(--radius-md);
  --breadcrumb-menu-border: var(--color-border);
  --breadcrumb-menu-bg: var(--color-popover);
  --breadcrumb-menu-fg: var(--color-popover-foreground);
  --breadcrumb-menu-shadow: var(--shadow-md);
  --breadcrumb-menu-item-radius: var(--radius-sm);
  --breadcrumb-menu-item-px: 8px;
  --breadcrumb-menu-item-py: 6px;
  --breadcrumb-menu-item-font-size: 14px;
  --breadcrumb-menu-item-highlight-bg: var(--color-accent);
  --breadcrumb-menu-item-highlight-fg: var(--color-accent-foreground);
}

import { ark } from "@ark-ui/react/factory";
import { cva, type VariantProps } from "class-variance-authority";
import type { ComponentPropsWithoutRef } from "react";
import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex cursor-pointer items-center justify-center gap-2 whitespace-nowrap font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-(--btn-ring) focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-(--btn-disabled-opacity) [&_svg]:pointer-events-none [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        solid:
          "bg-(--btn-solid-bg) text-(--btn-solid-fg) hover:bg-(--btn-solid-bg-hover) [box-shadow:var(--btn-solid-shadow)]",
        outline:
          "border border-(--btn-outline-border) text-(--btn-outline-fg) hover:bg-(--btn-outline-bg-hover)",
        ghost:
          "text-(--btn-ghost-fg) hover:bg-(--btn-ghost-bg-hover)",
        link:
          "text-(--btn-link-fg) underline-offset-4 hover:underline",
      },
      size: {
        sm: "h-(--btn-sm-height) px-(--btn-sm-px) [font-size:var(--btn-sm-font-size)] rounded-(--btn-radius)",
        md: "h-(--btn-md-height) px-(--btn-md-px) [font-size:var(--btn-md-font-size)] rounded-(--btn-radius)",
        lg: "h-(--btn-lg-height) px-(--btn-lg-px) [font-size:var(--btn-lg-font-size)] rounded-(--btn-radius)",
      },
    },
    defaultVariants: {
      variant: "solid",
      size: "md",
    },
  },
);
export type ButtonProps = ComponentPropsWithoutRef<typeof ark.button> &
  VariantProps<typeof buttonVariants> & {
    asChild?: boolean;
  };
export function Button({
  className,
  variant,
  size,
  asChild = false,
  ...props
}: ButtonProps) {
  return (
    <ark.button
      asChild={asChild}
      className={cn(buttonVariants({ variant, size }), className)}
      {...props}
    />
  );
}

/* Button component tokens — override these to customise the button. */
:root {
  /* Solid variant */
  --btn-solid-bg: var(--color-primary);
  --btn-solid-fg: var(--color-primary-foreground);
  --btn-solid-bg-hover: oklch(from var(--color-primary) calc(l - 0.06) c h);
  /* visual-button-shadow-anatomy: six-layer shadow for depth and polish */
  --btn-solid-shadow:
    0 0 0 0.5px oklch(0 0 0 / 0.2), inset 0 0 0 1px oklch(1 1 1 / 0.04),
    inset 0 1px 0 oklch(1 1 1 / 0.07), 0 1px 2px oklch(0 0 0 / 0.1), 0 2px 4px oklch(0 0 0 / 0.06),
    0 4px 8px oklch(0 0 0 / 0.03);

  /* Outline variant */
  --btn-outline-border: var(--color-border);
  --btn-outline-fg: var(--color-foreground);
  --btn-outline-bg-hover: var(--color-accent);

  /* Ghost variant */
  --btn-ghost-fg: var(--color-foreground);
  --btn-ghost-bg-hover: var(--color-accent);

  /* Link variant */
  --btn-link-fg: var(--color-primary);

  /* Shared */
  --btn-radius: var(--radius-md);
  --btn-ring: var(--color-ring);
  --btn-disabled-opacity: 0.5;

  /* Size: sm */
  --btn-sm-height: 32px;
  --btn-sm-px: 12px;
  --btn-sm-font-size: 13px;

  /* Size: md */
  --btn-md-height: 36px;
  --btn-md-px: 16px;
  --btn-md-font-size: 14px;

  /* Size: lg */
  --btn-lg-height: 40px;
  --btn-lg-px: 20px;
  --btn-lg-font-size: 15px;
}

